import type * as React from "react";

import type { PrototypeCardProps } from "../mock-prototype-auth/PrototypeCard";

/**
 * Content for a globally hosted prototype note card (portal + high z-index).
 * Mirrors {@link PrototypeCardProps} except `children` is optional for overlay-only copy.
 */
export type PrototypeOverlayOptions = Omit<Partial<PrototypeCardProps>, "children"> & {
  children?: React.ReactNode;
  /** Corner placement of the card within the viewport. @default "top-right" */
  placement?: "top-right" | "top-left" | "bottom-right" | "bottom-left";
  /** Accessible label for the overlay region. */
  overlayAriaLabel?: string;
};

import * as React from "react";
import { createPortal } from "react-dom";
import { X } from "lucide-react";

import { Button } from "@procertus-ui/ui";

import { PrototypeCard } from "../mock-prototype-auth/PrototypeCard";
import { cn } from "../lib/utils";

import type { PrototypeOverlayOptions } from "./prototype-overlay-types";

// Above app chrome and default dialog stack (e.g. dialog content uses z-40 in @procertus-ui/ui).
const OVERLAY_Z = "z-[100]";

const placementClass: Record<NonNullable<PrototypeOverlayOptions["placement"]>, string> = {
  "top-right": "top-4 right-4",
  "top-left": "top-4 left-4",
  "bottom-right": "bottom-4 right-4",
  "bottom-left": "bottom-4 left-4",
};

export type PrototypeOverlayDispatch = {
  /** Show or replace the global prototype overlay card (portal to `document.body`). */
  show: (options: PrototypeOverlayOptions) => void;
  /** Start exit transition, then unmount. Safe to call when already dismissed. */
  dismiss: () => void;
};

const PrototypeOverlayContext = React.createContext<PrototypeOverlayDispatch | undefined>(
  undefined,
);

export type PrototypeOverlayProviderProps = {
  children: React.ReactNode;
};

/**
 * Single host for “prototype question” cards: imperative API (like {@link DialogProvider}),
 * fixed positioning, enter/exit transitions, dismiss control, and stacking above the rest of the UI.
 */
export function PrototypeOverlayProvider({ children }: PrototypeOverlayProviderProps) {
  const [payload, setPayload] = React.useState<PrototypeOverlayOptions | null>(null);
  const [entered, setEntered] = React.useState(false);
  const exitClearTimerRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);
  const [mounted, setMounted] = React.useState(false);

  React.useEffect(() => {
    setMounted(true);
  }, []);

  const dismiss = React.useCallback(() => {
    setEntered(false);
  }, []);

  const show = React.useCallback((options: PrototypeOverlayOptions) => {
    if (exitClearTimerRef.current != null) {
      clearTimeout(exitClearTimerRef.current);
      exitClearTimerRef.current = null;
    }
    setPayload(options);
    setEntered(false);
    requestAnimationFrame(() => {
      requestAnimationFrame(() => setEntered(true));
    });
  }, []);

  const handleTransitionEnd = React.useCallback(
    (event: React.TransitionEvent<HTMLDivElement>) => {
      if (event.propertyName !== "opacity" || entered) return;
      setPayload(null);
    },
    [entered],
  );

  React.useEffect(() => {
    if (entered || !payload) return;
    const ms = 220;
    exitClearTimerRef.current = setTimeout(() => {
      setPayload(null);
      exitClearTimerRef.current = null;
    }, ms);
    return () => {
      if (exitClearTimerRef.current != null) {
        clearTimeout(exitClearTimerRef.current);
        exitClearTimerRef.current = null;
      }
    };
  }, [entered, payload]);

  const value = React.useMemo<PrototypeOverlayDispatch>(() => ({ show, dismiss }), [dismiss, show]);

  const portal =
    mounted && payload && typeof document !== "undefined"
      ? createPortal(
          <div
            className={cn("pointer-events-none fixed inset-0", OVERLAY_Z)}
            aria-hidden={!entered}
          >
            <div
              className={cn(
                "pointer-events-auto absolute w-[min(22rem,calc(100vw-2rem))] text-left shadow-(--shadow-proc-md)",
                placementClass[payload.placement ?? "top-right"],
                "transition-[opacity,transform] duration-200 ease-out",
                entered ? "translate-y-0 opacity-100" : "-translate-y-1 opacity-0",
              )}
              role="dialog"
              aria-modal="false"
              aria-label={payload.overlayAriaLabel ?? "Prototype-notitie"}
              aria-hidden={!entered}
              onTransitionEnd={handleTransitionEnd}
            >
              <div className="relative">
                <Button
                  type="button"
                  variant="ghost"
                  size="icon-sm"
                  className="absolute top-2 left-2 z-20 h-8 w-8 text-muted-foreground hover:text-foreground"
                  onClick={dismiss}
                  aria-label="Sluiten"
                >
                  <X className="size-4" aria-hidden />
                </Button>
                <PrototypeCard
                  title={payload.title}
                  description={payload.description}
                  notice={payload.notice}
                  showDemoBadge={payload.showDemoBadge}
                  demoBadgeLabel={payload.demoBadgeLabel}
                  demoBadgeTitle={payload.demoBadgeTitle}
                  className={cn("pt-10", payload.className)}
                  cardContentClassName={payload.cardContentClassName}
                >
                  {payload.children ?? null}
                </PrototypeCard>
              </div>
            </div>
          </div>,
          document.body,
        )
      : null;

  return (
    <PrototypeOverlayContext.Provider value={value}>
      {children}
      {portal}
    </PrototypeOverlayContext.Provider>
  );
}

export function usePrototypeOverlay(): PrototypeOverlayDispatch {
  const ctx = React.useContext(PrototypeOverlayContext);
  if (ctx === undefined) {
    throw new Error("usePrototypeOverlay must be used within a PrototypeOverlayProvider");
  }
  return ctx;
}

import * as React from "react";
import { createPortal } from "react-dom";
import { X } from "lucide-react";

import { Button } from "@procertus-ui/ui";

import { PrototypeCard } from "../mock-prototype-auth/PrototypeCard";
import { cn } from "../lib/utils";

import type { PrototypeOverlayOptions } from "./prototype-overlay-types";

// Above app chrome and default dialog stack (e.g. dialog content uses z-40 in @procertus-ui/ui).
const OVERLAY_Z = "z-[100]";

const placementClass: Record<NonNullable<PrototypeOverlayOptions["placement"]>, string> = {
  "top-right": "top-4 right-4",
  "top-left": "top-4 left-4",
  "bottom-right": "bottom-4 right-4",
  "bottom-left": "bottom-4 left-4",
};

export type PrototypeOverlayDispatch = {
  /** Show or replace the global prototype overlay card (portal to `document.body`). */
  show: (options: PrototypeOverlayOptions) => void;
  /** Start exit transition, then unmount. Safe to call when already dismissed. */
  dismiss: () => void;
};

const PrototypeOverlayContext = React.createContext<PrototypeOverlayDispatch | undefined>(
  undefined,
);

export type PrototypeOverlayProviderProps = {
  children: React.ReactNode;
};

/**
 * Single host for “prototype question” cards: imperative API (like {@link DialogProvider}),
 * fixed positioning, enter/exit transitions, dismiss control, and stacking above the rest of the UI.
 */
export function PrototypeOverlayProvider({ children }: PrototypeOverlayProviderProps) {
  const [payload, setPayload] = React.useState<PrototypeOverlayOptions | null>(null);
  const [entered, setEntered] = React.useState(false);
  const enteredRef = React.useRef(false);

  React.useLayoutEffect(() => {
    enteredRef.current = entered;
  }, [entered]);

  const [mounted, setMounted] = React.useState(false);
  React.useEffect(() => {
    setMounted(true);
  }, []);

  const dismiss = React.useCallback(() => {
    setEntered(false);
  }, []);

  const show = React.useCallback((options: PrototypeOverlayOptions) => {
    setPayload(options);
    if (enteredRef.current) {
      return;
    }
    setEntered(false);
    requestAnimationFrame(() => {
      requestAnimationFrame(() => setEntered(true));
    });
  }, []);

  const handleTransitionEnd = React.useCallback(
    (event: React.TransitionEvent<HTMLDivElement>) => {
      if (event.propertyName !== "opacity") return;
      if (!enteredRef.current) {
        setPayload(null);
      }
    },
    [],
  );

  // Fallback if transition end does not fire (e.g. tab backgrounded).
  React.useEffect(() => {
    if (entered || !payload) return;
    const t = window.setTimeout(() => setPayload(null), 280);
    return () => window.clearTimeout(t);
  }, [entered, payload]);

  const value = React.useMemo<PrototypeOverlayDispatch>(() => ({ show, dismiss }), [dismiss, show]);

  const portal =
    mounted && payload && typeof document !== "undefined"
      ? createPortal(
          <div className={cn("pointer-events-none fixed inset-0", OVERLAY_Z)}>
            <div
              className={cn(
                "pointer-events-auto absolute w-[min(22rem,calc(100vw-2rem))] text-left shadow-(--shadow-proc-md)",
                placementClass[payload.placement ?? "top-right"],
                "transition-[opacity,transform] duration-200 ease-out will-change-[opacity,transform]",
                entered ? "translate-y-0 opacity-100" : "-translate-y-1 opacity-0",
              )}
              role="dialog"
              aria-modal="false"
              aria-label={payload.overlayAriaLabel ?? "Prototype-notitie"}
              onTransitionEnd={handleTransitionEnd}
            >
              <div className="relative">
                <Button
                  type="button"
                  variant="ghost"
                  size="icon-sm"
                  className="absolute top-2 left-2 z-20 h-8 w-8 text-muted-foreground hover:text-foreground"
                  onClick={dismiss}
                  aria-label="Sluiten"
                >
                  <X className="size-4" aria-hidden />
                </Button>
                <PrototypeCard
                  title={payload.title}
                  description={payload.description}
                  notice={payload.notice}
                  showDemoBadge={payload.showDemoBadge}
                  demoBadgeLabel={payload.demoBadgeLabel}
                  demoBadgeTitle={payload.demoBadgeTitle}
                  className={cn("pt-10", payload.className)}
                  cardContentClassName={payload.cardContentClassName}
                >
                  {payload.children ?? null}
                </PrototypeCard>
              </div>
            </div>
          </div>,
          document.body,
        )
      : null;

  return (
    <PrototypeOverlayContext.Provider value={value}>
      {children}
      {portal}
    </PrototypeOverlayContext.Provider>
  );
}

export function usePrototypeOverlay(): PrototypeOverlayDispatch {
  const ctx = React.useContext(PrototypeOverlayContext);
  if (ctx === undefined) {
    throw new Error("usePrototypeOverlay must be used within a PrototypeOverlayProvider");
  }
  return ctx;
}

